def _model_to_nested(model: Model) -> ModelNested:
    """Convert flat Model to nested format."""
    attrs = ModelAttributes()
    _populate_model_attrs(attrs, model)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        model, _MODEL_REL_FIELDS, ModelRelationshipAttributes
    )
    return ModelNested(
        guid=model.guid,
        type_name=model.type_name,
        status=model.status,
        version=model.version,
        create_time=model.create_time,
        update_time=model.update_time,
        created_by=model.created_by,
        updated_by=model.updated_by,
        classifications=model.classifications,
        classification_names=model.classification_names,
        meanings=model.meanings,
        labels=model.labels,
        business_attributes=model.business_attributes,
        custom_attributes=model.custom_attributes,
        pending_tasks=model.pending_tasks,
        proxy=model.proxy,
        is_incomplete=model.is_incomplete,
        provenance_type=model.provenance_type,
        home_id=model.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _model_from_nested(nested: ModelNested) -> Model:
    """Convert nested format to flat Model."""
    attrs = nested.attributes if nested.attributes is not UNSET else ModelAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _MODEL_REL_FIELDS,
        ModelRelationshipAttributes,
    )
    return Model(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_model_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _model_to_nested_bytes(model: Model, serde: Serde) -> bytes:
    """Convert flat Model to nested JSON bytes."""
    return serde.encode(_model_to_nested(model))


def _model_from_nested_bytes(data: bytes, serde: Serde) -> Model:
    """Convert nested JSON bytes to flat Model."""
    nested = serde.decode(data, ModelNested)
    return _model_from_nested(nested)


